import argparse
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, configs):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=configs)
    admin_client.create_topics(new_topics=[topic], validate_only=False)

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Script')
    parser.add_argument('--bootstrap-server', required=True, help='Kafka bootstrap server')
    parser.add_argument('--create-topic', help='Name of the topic to create')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions for the topic')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor for the topic')
    parser.add_argument('--config', action='append', help='Topic configuration in key=value format', default=[])

    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_server)

    if args.create_topic:
        configs = dict(config.split('=') for config in args.config)
        create_topic(admin_client, args.create_topic, args.partitions, args.replication_factor, configs)

    admin_client.close()

if __name__ == '__main__':
    main()